module top_module(
    input clk,
    input parallel_load,
    input serial_in,
    output serial_out,
    input [3:0] data_in
);reg [3:0] shift_reg;

    always @(posedge clk) begin
        if (parallel_load) begin
            shift_reg <= data_in;
        end else begin
            shift_reg <= {shift_reg[2:0], serial_in};
        end
    end

    assign serial_out = shift_reg[0];

endmodule
